import React, { useState, useEffect, useRef } from 'react';
import { create, all } from 'mathjs';
import { CalcSubMode, AngleMode } from '../types';

const math = create(all);

const Calculator: React.FC = () => {
  const [expression, setExpression] = useState('');
  const [result, setResult] = useState<string | null>(null);
  const [subMode, setSubMode] = useState<CalcSubMode>('SCIENTIFIC');
  const [angleMode, setAngleMode] = useState<AngleMode>('DEG');
  const [history, setHistory] = useState<string[]>([]);
  const displayRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (displayRef.current) {
      displayRef.current.scrollLeft = displayRef.current.scrollWidth;
    }
  }, [expression]);

  const handlePress = (key: string) => {
    if (key === 'C') {
      setExpression('');
      setResult(null);
    } else if (key === 'DEL') {
      setExpression(prev => prev.slice(0, -1));
    } else if (key === '=') {
      calculateResult();
    } else if (key === 'MODE') {
      setSubMode(prev => prev === 'SCIENTIFIC' ? 'COMMERCIAL' : 'SCIENTIFIC');
    } else if (key === 'DEG/RAD') {
      setAngleMode(prev => prev === 'DEG' ? 'RAD' : 'DEG');
    } else if (['sin', 'cos', 'tan', 'asin', 'acos', 'atan', 'log', 'ln', 'sqrt'].includes(key)) {
      setExpression(prev => prev + key + '(');
    } else {
      setExpression(prev => prev + key);
    }
  };

  const calculateResult = () => {
    try {
      let expr = expression;

      // Handle degree/radian conversion for trig functions
      if (angleMode === 'DEG') {
        expr = expr.replace(/sin\(([^)]+)\)/g, 'sin(($1) deg)');
        expr = expr.replace(/cos\(([^)]+)\)/g, 'cos(($1) deg)');
        expr = expr.replace(/tan\(([^)]+)\)/g, 'tan(($1) deg)');
      }

      const evalRes = math.evaluate(expr);
      const formatted = math.format(evalRes, { precision: 14 });
      setResult(formatted.toString());
      setHistory(prev => [expression + ' = ' + formatted, ...prev].slice(0, 5));
    } catch (err) {
      setResult('Error');
    }
  };

  const sciButtons = [
    ['MODE', 'DEG/RAD', '(', ')'],
    ['sin', 'cos', 'tan', 'log'],
    ['asin', 'acos', 'atan', 'ln'],
    ['sqrt', 'x^2', 'x!', '%'],
    ['7', '8', '9', '/'],
    ['4', '5', '6', '*'],
    ['1', '2', '3', '-'],
    ['C', '0', '.', '+'],
    ['DEL', '=']
  ];

  const commButtons = [
    ['MODE', 'TAX+', 'TAX-', 'GT'],
    ['7', '8', '9', '/'],
    ['4', '5', '6', '*'],
    ['1', '2', '3', '-'],
    ['C', '0', '.', '+'],
    ['DEL', '=']
  ];

  const buttons = subMode === 'SCIENTIFIC' ? sciButtons : commButtons;

  const getButtonClass = (btn: string) => {
    const base = "flex items-center justify-center rounded-xl p-4 text-sm font-semibold transition-all duration-200 active:scale-95 border border-slate-800 shadow-sm ";
    if (['C', 'DEL'].includes(btn)) return base + "bg-rose-500/10 text-rose-500 hover:bg-rose-500/20";
    if (btn === '=') return base + "bg-cyan-500 text-slate-950 hover:bg-cyan-400 col-span-2";
    if (['+', '-', '*', '/', 'MODE', 'DEG/RAD', '(', ')'].includes(btn)) return base + "bg-slate-800/50 text-cyan-400 hover:bg-slate-700/50";
    if (isNaN(Number(btn)) && btn !== '.') return base + "bg-slate-900/40 text-slate-400 hover:bg-slate-800/40";
    return base + "bg-slate-800/20 text-slate-200 hover:bg-slate-700/30";
  };

  return (
    <div className="flex flex-col h-full max-w-xl mx-auto p-4 animate-in fade-in duration-500">
      {/* Brand & Status Bar */}
      <div className="flex justify-between items-center mb-4 px-2">
        <div className="flex items-center gap-2">
          <span className="text-cyan-500 font-bold tracking-widest text-xs uppercase">SciCom 1905</span>
          <span className="px-1.5 py-0.5 rounded-md bg-cyan-500/10 text-cyan-500 text-[10px] font-bold border border-cyan-500/20">AETHER-X</span>
        </div>
        <div className="flex gap-4">
          <span className="text-[10px] font-medium text-slate-500 uppercase tracking-tighter">Mode: {subMode}</span>
          <span className="text-[10px] font-medium text-slate-500 uppercase tracking-tighter">Angle: {angleMode}</span>
        </div>
      </div>

      {/* Display Area */}
      <div className="bg-slate-900/40 rounded-3xl border border-slate-800 p-6 mb-6 flex flex-col justify-end items-end min-h-[180px] shadow-inner backdrop-blur-xl relative overflow-hidden group">
        <div className="absolute top-0 right-0 p-4 opacity-10 group-hover:opacity-30 transition-opacity">
           <svg className="w-24 h-24 text-cyan-500" fill="currentColor" viewBox="0 0 24 24"><path d="M19,13H5V11H19V13Z"/></svg>
        </div>
        <div className="flex flex-col gap-1 w-full text-right overflow-hidden">
          {history.length > 0 && (
            <div className="text-slate-500 text-sm mono truncate opacity-50 mb-2">
              {history[0]}
            </div>
          )}
          <div ref={displayRef} className="text-slate-100 text-3xl mono whitespace-nowrap overflow-x-auto scrollbar-hide py-1">
            {expression || '0'}
          </div>
          <div className="text-cyan-400 text-5xl font-bold mono truncate mt-2 drop-shadow-[0_0_8px_rgba(34,211,238,0.3)]">
            {result ? result : ''}
          </div>
        </div>
      </div>

      {/* Keypad */}
      <div className="grid grid-cols-4 gap-3">
        {buttons.flat().map((btn) => (
          <button
            key={btn}
            onClick={() => handlePress(btn)}
            className={getButtonClass(btn)}
          >
            {btn === 'x^2' ? <span>x<sup>2</sup></span> : btn}
          </button>
        ))}
      </div>
    </div>
  );
};

export default Calculator;

import React, { useState, useEffect } from 'react';
import { UnitCategory, Unit } from '../types';
import { UNIT_DATABASE } from '../constants';
import { ChevronRight, ArrowRightLeft, Search } from 'lucide-react';

const Converter: React.FC = () => {
  const [selectedCat, setSelectedCat] = useState<UnitCategory | null>(null);
  const [fromUnit, setFromUnit] = useState<Unit | null>(null);
  const [toUnit, setToUnit] = useState<Unit | null>(null);
  const [inputValue, setInputValue] = useState('1');
  const [outputValue, setOutputValue] = useState('0');
  const [searchQuery, setSearchQuery] = useState('');

  const categories = Object.keys(UNIT_DATABASE) as UnitCategory[];
  const filteredCategories = categories.filter(c => c.toLowerCase().includes(searchQuery.toLowerCase()));

  useEffect(() => {
    if (selectedCat && fromUnit && toUnit) {
      calculate();
    }
  }, [inputValue, fromUnit, toUnit, selectedCat]);

  const selectCategory = (cat: UnitCategory) => {
    setSelectedCat(cat);
    setFromUnit(UNIT_DATABASE[cat][0]);
    setToUnit(UNIT_DATABASE[cat][1] || UNIT_DATABASE[cat][0]);
  };

  const calculate = () => {
    if (!selectedCat || !fromUnit || !toUnit) return;

    try {
      const val = parseFloat(inputValue);
      if (isNaN(val)) {
        setOutputValue('0');
        return;
      }

      let res = 0;
      if (selectedCat === "Temperature") {
        const f = fromUnit.factor as string;
        const t = toUnit.factor as string;
        let celsius = val;

        if (f === "F") celsius = (val - 32) * 5 / 9;
        else if (f === "K") celsius = val - 273.15;
        else if (f === "R") celsius = (val - 491.67) * 5 / 9;

        if (t === "C") res = celsius;
        else if (t === "F") res = (celsius * 9 / 5) + 32;
        else if (t === "K") res = celsius + 273.15;
        else if (t === "R") res = (celsius * 9 / 5) + 491.67;
      } else {
        const fromFactor = fromUnit.factor as number;
        const toFactor = toUnit.factor as number;
        res = (val * fromFactor) / toFactor;
      }

      // Format result nicely
      const formatted = res.toLocaleString(undefined, { 
        maximumFractionDigits: 8,
        useGrouping: false
      });
      setOutputValue(formatted);
    } catch (e) {
      setOutputValue('Error');
    }
  };

  const handleKeypad = (k: string) => {
    if (k === 'CLR') setInputValue('0');
    else if (k === '.') {
      if (!inputValue.includes('.')) setInputValue(prev => prev + '.');
    } else {
      setInputValue(prev => prev === '0' ? k : prev + k);
    }
  };

  if (!selectedCat) {
    return (
      <div className="flex flex-col h-full max-w-2xl mx-auto p-4 animate-in fade-in slide-in-from-bottom-4 duration-500">
        <div className="mb-8">
          <h2 className="text-3xl font-bold text-slate-100 mb-2">UniVerse Pro</h2>
          <p className="text-slate-500 text-sm">Professional scale converter across 20+ disciplines.</p>
        </div>

        <div className="relative mb-6">
          <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-500 w-5 h-5" />
          <input 
            type="text" 
            placeholder="Search disciplines..."
            className="w-full bg-slate-900/50 border border-slate-800 rounded-2xl py-4 pl-12 pr-4 text-slate-100 placeholder:text-slate-600 focus:outline-none focus:ring-2 focus:ring-cyan-500/50"
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
          />
        </div>

        <div className="grid grid-cols-1 sm:grid-cols-2 gap-3 overflow-y-auto pb-10 pr-2">
          {filteredCategories.map(cat => (
            <button
              key={cat}
              onClick={() => selectCategory(cat)}
              className="group flex items-center justify-between p-5 bg-slate-900/30 border border-slate-800/50 rounded-2xl hover:bg-slate-800/40 hover:border-slate-700 transition-all duration-300"
            >
              <div className="flex flex-col items-start">
                <span className="text-slate-200 font-semibold group-hover:text-cyan-400 transition-colors">{cat}</span>
                <span className="text-[10px] text-slate-500 uppercase tracking-widest">{UNIT_DATABASE[cat].length} units available</span>
              </div>
              <ChevronRight className="w-5 h-5 text-slate-600 group-hover:text-cyan-400 group-hover:translate-x-1 transition-all" />
            </button>
          ))}
        </div>
      </div>
    );
  }

  return (
    <div className="flex flex-col h-full max-w-xl mx-auto p-4 animate-in fade-in duration-500">
      <div className="flex items-center justify-between mb-8">
        <button onClick={() => setSelectedCat(null)} className="text-sm text-slate-500 hover:text-cyan-400 flex items-center gap-1 transition-colors">
          <ArrowRightLeft className="w-4 h-4 rotate-90" />
          Back to List
        </button>
        <span className="px-3 py-1 bg-cyan-500/10 text-cyan-400 rounded-full text-xs font-bold border border-cyan-500/20 uppercase tracking-widest">
          {selectedCat}
        </span>
      </div>

      <div className="bg-slate-900/40 rounded-3xl border border-slate-800 p-8 mb-8 backdrop-blur-xl shadow-2xl space-y-8">
        <div className="space-y-4">
          <label className="text-[10px] uppercase font-bold tracking-widest text-slate-500 ml-1">From</label>
          <div className="flex flex-col gap-2">
            <select 
              className="bg-transparent text-slate-300 text-lg focus:outline-none cursor-pointer hover:text-cyan-400 transition-colors"
              value={fromUnit?.name}
              onChange={(e) => setFromUnit(UNIT_DATABASE[selectedCat].find(u => u.name === e.target.value) || null)}
            >
              {UNIT_DATABASE[selectedCat].map(u => <option key={u.name} value={u.name} className="bg-slate-900">{u.name}</option>)}
            </select>
            <div className="text-4xl font-light mono text-slate-100 overflow-x-auto whitespace-nowrap scrollbar-hide">
              {inputValue}
            </div>
          </div>
        </div>

        <div className="relative h-[2px] bg-slate-800/50">
           <div className="absolute left-1/2 top-1/2 -translate-x-1/2 -translate-y-1/2 p-2 bg-slate-900 rounded-full border border-slate-800">
             <ArrowRightLeft className="w-4 h-4 text-cyan-500" />
           </div>
        </div>

        <div className="space-y-4">
          <label className="text-[10px] uppercase font-bold tracking-widest text-slate-500 ml-1">To</label>
          <div className="flex flex-col gap-2">
            <select 
              className="bg-transparent text-slate-300 text-lg focus:outline-none cursor-pointer hover:text-cyan-400 transition-colors"
              value={toUnit?.name}
              onChange={(e) => setToUnit(UNIT_DATABASE[selectedCat].find(u => u.name === e.target.value) || null)}
            >
              {UNIT_DATABASE[selectedCat].map(u => <option key={u.name} value={u.name} className="bg-slate-900">{u.name}</option>)}
            </select>
            <div className="text-5xl font-bold mono text-cyan-400 truncate drop-shadow-[0_0_15px_rgba(34,211,238,0.2)]">
              {outputValue}
            </div>
          </div>
        </div>
      </div>

      <div className="grid grid-cols-3 gap-3">
        {['1','2','3','4','5','6','7','8','9','.', '0', 'CLR'].map(k => (
          <button 
            key={k} 
            onClick={() => handleKeypad(k)}
            className={`flex items-center justify-center p-6 rounded-2xl font-bold text-xl transition-all active:scale-95 border border-slate-800 shadow-sm
              ${k === 'CLR' ? 'bg-rose-500/10 text-rose-500 hover:bg-rose-500/20' : 'bg-slate-800/20 text-slate-200 hover:bg-slate-700/30'}`}
          >
            {k}
          </button>
        ))}
      </div>
    </div>
  );
};

export default Converter;

import React, { useState, useEffect } from 'react';
import { AppMode } from './types';
import Calculator from './components/Calculator';
import Converter from './components/Converter';
import { Calculator as CalcIcon, Repeat, LayoutGrid, Zap } from 'lucide-react';

const App: React.FC = () => {
  const [mode, setMode] = useState<AppMode>('CALCULATOR');
  const [isLoaded, setIsLoaded] = useState(false);

  useEffect(() => {
    // Splash screen animation
    const timer = setTimeout(() => setIsLoaded(true), 2500);
    return () => clearTimeout(timer);
  }, []);

  if (!isLoaded) {
    return (
      <div className="fixed inset-0 bg-slate-950 flex flex-col items-center justify-center p-6 text-center animate-in fade-in duration-500">
        <div className="relative mb-12">
          <div className="absolute inset-0 bg-cyan-500 blur-3xl opacity-20 animate-pulse"></div>
          <Zap className="w-24 h-24 text-cyan-500 relative z-10 animate-bounce" />
        </div>
        <h1 className="text-5xl font-black text-white tracking-tighter mb-4">
          OMNISENSE <span className="text-cyan-500">PRO</span>
        </h1>
        <p className="text-slate-500 text-lg font-medium tracking-widest uppercase max-w-xs leading-tight">
          High-Performance Dual-Engine Suite
        </p>
        <div className="mt-12 w-48 h-1 bg-slate-900 rounded-full overflow-hidden">
          <div className="h-full bg-cyan-500 animate-[loading_2.5s_ease-in-out_forwards]"></div>
        </div>
        <p className="fixed bottom-12 text-slate-700 text-[10px] uppercase font-bold tracking-[0.3em]">
          Powered by AETHER-X PRO Architecture
        </p>
        <style>{`
          @keyframes loading {
            0% { width: 0% }
            100% { width: 100% }
          }
        `}</style>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-slate-950 flex flex-col items-center">
      {/* Dynamic Background */}
      <div className="fixed inset-0 pointer-events-none overflow-hidden -z-10">
        <div className="absolute -top-1/4 -right-1/4 w-[600px] h-[600px] bg-cyan-500/5 blur-[120px] rounded-full animate-pulse"></div>
        <div className="absolute -bottom-1/4 -left-1/4 w-[600px] h-[600px] bg-blue-500/5 blur-[120px] rounded-full animate-pulse delay-700"></div>
      </div>

      {/* Main Content Area */}
      <main className="flex-1 w-full max-w-4xl pt-16 pb-24 px-4 overflow-y-auto">
        {mode === 'CALCULATOR' ? <Calculator /> : <Converter />}
