      {/* Bottom Navigation */}
      <nav className="fixed bottom-8 left-1/2 -translate-x-1/2 bg-slate-900/40 backdrop-blur-2xl border border-slate-800 p-2 rounded-3xl shadow-2xl flex items-center gap-1 z-50">
        <button
          onClick={() => setMode('CALCULATOR')}
          className={`flex items-center gap-2 px-6 py-3 rounded-2xl transition-all duration-300 ${
            mode === 'CALCULATOR' 
              ? 'bg-cyan-500 text-slate-950 font-bold shadow-lg shadow-cyan-500/20' 
              : 'text-slate-400 hover:text-white hover:bg-slate-800/50'
          }`}
        >
          <CalcIcon className="w-5 h-5" />
          <span className="text-sm">Calculator</span>
        </button>
        <button
          onClick={() => setMode('CONVERTER')}
          className={`flex items-center gap-2 px-6 py-3 rounded-2xl transition-all duration-300 ${
