import React, { useState, useEffect, useRef } from 'react';
import { create, all } from 'mathjs';
import { CalcSubMode, AngleMode } from '../types';

const math = create(all);

const Calculator: React.FC = () => {
  const [expression, setExpression] = useState('');
  const [result, setResult] = useState<string | null>(null);
  const [subMode, setSubMode] = useState<CalcSubMode>('SCIENTIFIC');
  const [angleMode, setAngleMode] = useState<AngleMode>('DEG');
  const [history, setHistory] = useState<string[]>([]);
  const displayRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (displayRef.current) {
      displayRef.current.scrollLeft = displayRef.current.scrollWidth;
    }
  }, [expression]);

  const handlePress = (key: string) => {
    if (key === 'C') {
      setExpression('');
      setResult(null);
    } else if (key === 'DEL') {
      setExpression(prev => prev.slice(0, -1));
    } else if (key === '=') {
      calculateResult();
    } else if (key === 'MODE') {
      setSubMode(prev => prev === 'SCIENTIFIC' ? 'COMMERCIAL' : 'SCIENTIFIC');
    } else if (key === 'DEG/RAD') {
      setAngleMode(prev => prev === 'DEG' ? 'RAD' : 'DEG');
    } else if (['sin', 'cos', 'tan', 'asin', 'acos', 'atan', 'log', 'ln', 'sqrt', 'abs', 'mean', 'std', 'median'].includes(key)) {
      setExpression(prev => prev + key + '(');
    } else if (key === 'x^y') {
      setExpression(prev => prev + '^');
    } else if (key === 'pi') {
      setExpression(prev => prev + 'pi');
    } else if (key === 'e') {
      setExpression(prev => prev + 'e');
    } else if (key === 'mod') {
      setExpression(prev => prev + ' mod ');
    } else {
      setExpression(prev => prev + key);
    }
  };

  const calculateResult = () => {
    try {
      let expr = expression;

      // Handle degree/radian conversion for trig functions
      if (angleMode === 'DEG') {
        expr = expr.replace(/sin\(([^)]+)\)/g, 'sin(($1) deg)');
        expr = expr.replace(/cos\(([^)]+)\)/g, 'cos(($1) deg)');
        expr = expr.replace(/tan\(([^)]+)\)/g, 'tan(($1) deg)');
        expr = expr.replace(/asin\(([^)]+)\)/g, 'asin($1) to deg');
        expr = expr.replace(/acos\(([^)]+)\)/g, 'acos($1) to deg');
        expr = expr.replace(/atan\(([^)]+)\)/g, 'atan($1) to deg');
      }

      const evalRes = math.evaluate(expr);
      const formatted = math.format(evalRes, { precision: 14 });
      const resultStr = formatted.toString();
      setResult(resultStr);
      setHistory(prev => [expression + ' = ' + resultStr, ...prev].slice(0, 5));
    } catch (err) {
      setResult('Error');
    }
  };

  const sciButtons = [
    ['MODE', 'DEG/RAD', '(', ')'],
    ['sin', 'cos', 'tan', 'log'],
    ['asin', 'acos', 'atan', 'ln'],
    ['abs', 'mod', 'pi', 'e'],
    ['sqrt', 'x^y', 'x!', ','],
    ['mean', 'std', 'median', '%'],
    ['7', '8', '9', '/'],
    ['4', '5', '6', '*'],
    ['1', '2', '3', '-'],
    ['C', '0', '.', '+'],
    ['DEL', '=']
  ];

  const commButtons = [
    ['MODE', 'TAX+', 'TAX-', 'GT'],
    ['7', '8', '9', '/'],
    ['4', '5', '6', '*'],
    ['1', '2', '3', '-'],
    ['C', '0', '.', '+'],
    ['DEL', '=']
  ];

  const buttons = subMode === 'SCIENTIFIC' ? sciButtons : commButtons;

  const getButtonClass = (btn: string) => {
    const base = "flex items-center justify-center rounded-xl p-3.5 text-xs sm:text-sm font-semibold transition-all duration-200 active:scale-95 border border-slate-800 shadow-sm ";
    if (['C', 'DEL'].includes(btn)) return base + "bg-rose-500/10 text-rose-500 hover:bg-rose-500/20";
    if (btn === '=') return base + "bg-cyan-500 text-slate-950 hover:bg-cyan-400 col-span-2";
    if (['+', '-', '*', '/', 'MODE', 'DEG/RAD', '(', ')'].includes(btn)) return base + "bg-slate-800/50 text-cyan-400 hover:bg-slate-700/50";
    if (isNaN(Number(btn)) && btn !== '.') return base + "bg-slate-900/40 text-slate-400 hover:bg-slate-800/40";
    return base + "bg-slate-800/20 text-slate-200 hover:bg-slate-700/30";
  };

  return (
    <div className="flex flex-col h-full max-w-xl mx-auto p-4 animate-in fade-in duration-500 pb-20">
      {/* Brand & Status Bar */}
      <div className="flex justify-between items-center mb-4 px-2">
        <div className="flex items-center gap-2">
          <span className="text-cyan-500 font-bold tracking-widest text-[10px] uppercase">SciCom 1905</span>
          <span className="px-1.5 py-0.5 rounded-md bg-cyan-500/10 text-cyan-500 text-[8px] font-bold border border-cyan-500/20">AETHER-X</span>
        </div>
        <div className="flex gap-4">
          <span className="text-[9px] font-medium text-slate-500 uppercase tracking-tighter">M: {subMode}</span>
          <span className="text-[9px] font-medium text-slate-500 uppercase tracking-tighter">A: {angleMode}</span>
        </div>
      </div>

      {/* Display Area */}
      <div className="bg-slate-900/40 rounded-3xl border border-slate-800 p-6 mb-6 flex flex-col justify-end items-end min-h-[160px] shadow-inner backdrop-blur-xl relative overflow-hidden group">
        <div className="absolute top-0 right-0 p-4 opacity-10 group-hover:opacity-30 transition-opacity pointer-events-none">
           <svg className="w-20 h-20 text-cyan-500" fill="currentColor" viewBox="0 0 24 24"><path d="M19,13H5V11H19V13Z"/></svg>
        </div>
        <div className="flex flex-col gap-1 w-full text-right overflow-hidden relative z-10">
          {history.length > 0 && (
            <div className="text-slate-500 text-xs mono truncate opacity-50 mb-1">
              {history[0]}
            </div>
          )}
          <div ref={displayRef} className="text-slate-100 text-2xl mono whitespace-nowrap overflow-x-auto scrollbar-hide py-1">
            {expression || '0'}
          </div>
          <div className="text-cyan-400 text-4xl font-bold mono truncate mt-1 drop-shadow-[0_0_8px_rgba(34,211,238,0.3)]">
            {result ? result : ''}
          </div>
        </div>
      </div>

      {/* Keypad */}
      <div className="grid grid-cols-4 gap-2.5">
        {buttons.flat().map((btn, idx) => (
          <button
            key={`${btn}-${idx}`}
            onClick={() => handlePress(btn)}
            className={getButtonClass(btn)}
          >
            {btn === 'x^y' ? <span>x<sup>y</sup></span> : 
             btn === 'pi' ? 'π' :
             btn === 'x!' ? 'n!' :
             btn}
          </button>
        ))}
      </div>
    </div>
  );
};

