    'TAX+', 'TAX-', 'GT', '/',
    '7', '8', '9', '*',
    '4', '5', '6', '-',
    '1', '2', '3', '+',
    'C', '0', '.', '=',
    'DEL'
  ];

  const getButtonClass = (btn: string, isSmall = false) => {
    const base = `flex items-center justify-center rounded-xl font-semibold transition-all duration-200 active:scale-95 border border-slate-800 shadow-sm ${isSmall ? 'p-2 text-[10px]' : 'p-3.5 sm:p-4 text-sm'}`;
    if (['C', 'DEL', 'CLR'].includes(btn)) return `${base} bg-rose-500/10 text-rose-500 hover:bg-rose-500/20`;
    if (btn === '=') return `${base} bg-cyan-500 text-slate-950 hover:bg-cyan-400 font-bold ${subMode === 'SCIENTIFIC' ? 'col-span-2' : ''}`;
    if (['+', '-', '*', '/', '(', ')', '%', 'mod'].includes(btn)) return `${base} bg-slate-800/50 text-cyan-400 hover:bg-slate-700/50`;
    if (['i', 're', 'im', 'conj', 'arg'].includes(btn)) return `${base} bg-indigo-500/10 text-indigo-400 hover:bg-indigo-500/20 border-indigo-500/20`;
    if (isNaN(Number(btn)) && btn !== '.') return `${base} bg-slate-900/40 text-slate-400 hover:bg-slate-800/40`;
    return `${base} bg-slate-800/20 text-slate-200 hover:bg-slate-700/30`;
  };

  return (
    <div className="flex flex-col h-full max-w-xl mx-auto p-2 sm:p-4 animate-in fade-in duration-500">
      {/* Brand & Status Bar */}
      <div className="flex justify-between items-center mb-3 px-2">
        <div className="flex items-center gap-2">
          <span className="text-cyan-500 font-bold tracking-widest text-[10px] uppercase">SciCom 1905</span>
          <div className="flex gap-1">
            <button 
              onClick={() => handlePress('MODE')}
              className="px-2 py-0.5 rounded bg-slate-800 text-slate-300 text-[9px] font-bold border border-slate-700 hover:bg-slate-700 uppercase transition-colors"
            >
              {subMode}
            </button>
            {subMode === 'SCIENTIFIC' && (
              <button 
                onClick={() => handlePress('DEG/RAD')}
                className="px-2 py-0.5 rounded bg-cyan-500/10 text-cyan-500 text-[9px] font-bold border border-cyan-500/20 hover:bg-cyan-500/20 uppercase transition-colors"
              >
                {angleMode}
              </button>
            )}
          </div>
        </div>
        <div className="text-[9px] font-bold text-slate-600 uppercase tracking-widest flex items-center gap-1.5">
          <div className="w-1.5 h-1.5 rounded-full bg-emerald-500 animate-pulse"></div>
          AETHER-X CORE
        </div>
      </div>

      {/* Enhanced Display Area */}
      <div className="bg-slate-900/60 rounded-3xl border border-slate-800 p-5 mb-5 flex flex-col justify-end items-end min-h-[140px] shadow-2xl backdrop-blur-xl relative overflow-hidden group ring-1 ring-slate-700/50">
        <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-transparent via-cyan-500/30 to-transparent"></div>
        <div className="flex flex-col gap-1 w-full text-right relative z-10">
          {history.length > 0 && (
            <div className="text-slate-500 text-xs mono truncate opacity-40 mb-1 h-4">
              {history[0]}
            </div>
          )}
          <div ref={displayRef} className="text-slate-300 text-xl mono whitespace-nowrap overflow-x-auto scrollbar-hide py-1">
            {expression || '0'}
          </div>
          <div className="flex items-center justify-end gap-3 mt-1 group/result">
            <div className="text-cyan-400 text-4xl sm:text-5xl font-bold mono truncate drop-shadow-[0_0_12px_rgba(34,211,238,0.4)]">
              {result ? result : ''}
            </div>
            {result && result !== 'Error' && (
              <button 
                onClick={copyToClipboard}
                className={`p-2 rounded-lg transition-all active:scale-90 ${copied ? 'bg-emerald-500/20 text-emerald-500' : 'text-slate-600 hover:text-slate-300 hover:bg-slate-800/50 opacity-0 group-hover/result:opacity-100'}`}
                title="Copy Result"
              >
                {copied ? <Check className="w-4 h-4" /> : <Copy className="w-4 h-4" />}
              </button>
            )}
          </div>
        </div>
      </div>

      {/* Scientific Mode - Expanded Multi-Grid Keypad */}
      {subMode === 'SCIENTIFIC' ? (
        <div className="flex flex-col gap-3">
          {/* Scientific Functions Grid (5x5) */}
          <div className="grid grid-cols-5 gap-2">
            {sciFuncs.map((btn, idx) => (
              <button key={`f-${idx}`} onClick={() => handlePress(btn)} className={getButtonClass(btn, true)}>
                {btn === 'x^y' ? <span>x<sup>y</sup></span> : btn === 'pi' ? 'π' : btn === 'x!' ? 'n!' : btn}
              </button>
            ))}
          </div>
          {/* Main Numeric Grid (4 columns) */}
          <div className="grid grid-cols-4 gap-2.5">
            {mainKeys.map((btn, idx) => (
              <button key={`m-${idx}`} onClick={() => handlePress(btn)} className={getButtonClass(btn)}>
                {btn}
              </button>
            ))}
          </div>
        </div>
      ) : (
        /* Commercial Mode Grid */
        <div className="grid grid-cols-4 gap-3">
          {commKeys.map((btn, idx) => (
            <button key={`c-${idx}`} onClick={() => handlePress(btn)} className={getButtonClass(btn)}>
              {btn}
            </button>
          ))}
        </div>
      )}
    </div>
  );
};

