import React, { useState, useEffect } from 'react';
import { UnitCategory, Unit } from '../types';
import { UNIT_DATABASE } from '../constants';
import { ChevronRight, ArrowRightLeft, Search, Copy, Check, Info, Cpu } from 'lucide-react';

const Converter: React.FC = () => {
  const [selectedCat, setSelectedCat] = useState<UnitCategory | null>(null);
  const [fromUnit, setFromUnit] = useState<Unit | null>(null);
  const [toUnit, setToUnit] = useState<Unit | null>(null);
  const [inputValue, setInputValue] = useState('1');
  const [outputValue, setOutputValue] = useState('0');
  const [searchQuery, setSearchQuery] = useState('');
  const [copied, setCopied] = useState(false);
  const [showFormula, setShowFormula] = useState(true);

  const categories = Object.keys(UNIT_DATABASE) as UnitCategory[];

  // Enhanced search: checks category names, unit names, and unit symbols
  const filteredCategories = categories.filter(cat => {
    const query = searchQuery.toLowerCase().trim();
    if (!query) return true;

    const catMatch = cat.toLowerCase().includes(query);
    const unitMatch = UNIT_DATABASE[cat].some(unit => 
      unit.name.toLowerCase().includes(query) || 
      unit.symbol.toLowerCase().includes(query)
    );

    return catMatch || unitMatch;
  }).sort((a, b) => a.localeCompare(b));

  useEffect(() => {
    if (selectedCat && fromUnit && toUnit) {
      calculate();
    }
  }, [inputValue, fromUnit, toUnit, selectedCat]);

  const selectCategory = (cat: UnitCategory) => {
    setSelectedCat(cat);
    setFromUnit(UNIT_DATABASE[cat][0]);
    setToUnit(UNIT_DATABASE[cat][1] || UNIT_DATABASE[cat][0]);
    setInputValue('1');
  };

  const swapUnits = () => {
    const temp = fromUnit;
    setFromUnit(toUnit);
    setToUnit(temp);
  };

  const calculate = () => {
    if (!selectedCat || !fromUnit || !toUnit) return;

    try {
      const val = parseFloat(inputValue);
      if (isNaN(val)) {
        setOutputValue('0');
        return;
      }

      let res = 0;
      if (selectedCat === "Temperature") {
        const f = fromUnit.factor as string;
        const t = toUnit.factor as string;
        let celsius = val;

        if (f === "F") celsius = (val - 32) * 5 / 9;
        else if (f === "K") celsius = val - 273.15;
        else if (f === "R") celsius = (val - 491.67) * 5 / 9;

        if (t === "C") res = celsius;
        else if (t === "F") res = (celsius * 9 / 5) + 32;
        else if (t === "K") res = celsius + 273.15;
        else if (t === "R") res = (celsius * 9 / 5) + 491.67;
      } else if (selectedCat === "Fuel Consumption") {
        const f = fromUnit.factor as string;
        const t = toUnit.factor as string;
        let l100 = val;
        if (f === "KML") l100 = 100 / val;
        else if (f === "MPG_US") l100 = 235.215 / val;
        else if (f === "MPG_UK") l100 = 282.481 / val;

        if (t === "L100") res = l100;
        else if (t === "KML") res = 100 / l100;
        else if (t === "MPG_US") res = 235.215 / l100;
        else if (t === "MPG_UK") res = 282.481 / l100;
      } else {
        const fromFactor = fromUnit.factor as number;
        const toFactor = toUnit.factor as number;
        res = (val * fromFactor) / toFactor;
      }

      const formatted = res.toLocaleString(undefined, { 
        maximumFractionDigits: 10,
        useGrouping: false
      });
      setOutputValue(formatted);
    } catch (e) {
      setOutputValue('Error');
    }
  };

  const getFormula = () => {
    if (!fromUnit || !toUnit || !selectedCat) return "";

    if (selectedCat === "Temperature") {
      if (fromUnit.name === toUnit.name) return "No conversion needed (Identity)";
      const pair = `${fromUnit.symbol} to ${toUnit.symbol}`;
      const formulas: Record<string, string> = {
        "°C to °F": "(°C × 9/5) + 32",
        "°F to °C": "(°F - 32) × 5/9",
        "°C to K": "°C + 273.15",
        "K to °C": "K - 273.15",
        "°F to K": "(°F - 32) × 5/9 + 273.15",
        "K to °F": "(K - 273.15) × 9/5 + 32",
        "°C to °R": "(°C + 273.15) × 9/5",
        "°R to °C": "(°R × 5/9) - 273.15"
      };
      return formulas[pair] || "Standard Thermodynamic Shift";
    }

    if (selectedCat === "Fuel Consumption") {
      if (fromUnit.name === toUnit.name) return "No conversion needed";
      if (fromUnit.symbol.includes('mpg') && toUnit.symbol === 'L/100km') {
        return `Constant (${fromUnit.factor === 'MPG_US' ? '235.215' : '282.481'}) / Value`;
      }
      return "Inverse Proportion Scaling";
    }

    const ratio = (fromUnit.factor as number) / (toUnit.factor as number);
    return `Value × ${ratio < 0.0001 ? ratio.toExponential(4) : ratio.toFixed(6).replace(/\.?0+$/, '')}`;
  };

  const handleKeypad = (k: string) => {
    if (k === 'CLR') setInputValue('0');
    else if (k === '.') {
      if (!inputValue.includes('.')) setInputValue(prev => prev + '.');
    } else {
      setInputValue(prev => prev === '0' ? k : prev + k);
    }
  };

  const copyToClipboard = () => {
    navigator.clipboard.writeText(outputValue);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  if (!selectedCat) {
    return (
      <div className="flex flex-col w-full max-w-2xl mx-auto px-2 animate-in fade-in slide-in-from-bottom-4 duration-500">
        <div className="mb-6 px-2">
          <h2 className="text-3xl font-black text-slate-100 tracking-tight mb-1">UNIVERSE <span className="text-cyan-500">PRO</span></h2>
          <p className="text-slate-500 text-xs font-bold uppercase tracking-widest">Master conversion engine with {categories.length} scientific modules</p>
        </div>

        <div className="sticky top-0 z-20 py-4 bg-slate-950/80 backdrop-blur-md px-2">
          <div className="relative">
            <div className="absolute left-6 top-1/2 -translate-y-1/2 text-slate-500">
              <Search className="w-5 h-5" />
            </div>
            <input 
              type="text" 
              placeholder="Search by name or symbol (e.g. 'meter', 'kg', 'psi')..."
              className="w-full bg-slate-900/60 border border-slate-800 rounded-2xl py-4 pl-14 pr-4 text-slate-100 placeholder:text-slate-600 focus:outline-none focus:ring-2 focus:ring-cyan-500/50 transition-all shadow-xl"
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
            />
          </div>
        </div>

        <div className="grid grid-cols-1 sm:grid-cols-2 gap-3 pb-32 mt-4 px-2">
          {filteredCategories.map(cat => (
            <button
              key={cat}
              onClick={() => selectCategory(cat)}
              className="group flex items-center justify-between p-5 bg-slate-900/30 border border-slate-800/50 rounded-2xl hover:bg-slate-800/60 hover:border-cyan-500/30 transition-all duration-300 active:scale-[0.98]"
            >
              <div className="flex flex-col items-start text-left">
                <span className="text-slate-200 font-bold tracking-tight group-hover:text-cyan-400 transition-colors">{cat}</span>
                <span className="text-[9px] text-slate-500 uppercase font-black tracking-[0.2em]">{UNIT_DATABASE[cat].length} METRICS</span>
              </div>
              <ChevronRight className="w-5 h-5 text-slate-700 group-hover:text-cyan-400 group-hover:translate-x-1 transition-all" />
            </button>
          ))}
          {filteredCategories.length === 0 && (
            <div className="col-span-full py-12 text-center">
              <p className="text-slate-600 font-bold uppercase tracking-widest text-xs">No matching metrics found</p>
            </div>
          )}
        </div>
      </div>
    );
  }

  return (
    <div className="flex flex-col w-full max-w-xl mx-auto px-2 animate-in fade-in duration-500">
      <div className="flex items-center justify-between mb-6 px-2">
        <button onClick={() => setSelectedCat(null)} className="text-[10px] font-black uppercase tracking-widest text-slate-500 hover:text-cyan-400 flex items-center gap-2 transition-colors group">
          <ArrowRightLeft className="w-4 h-4 rotate-90 group-hover:-translate-y-1 transition-transform" />
          Systems Library
        </button>
        <span className="px-4 py-1.5 bg-cyan-500/10 text-cyan-400 rounded-full text-[10px] font-black border border-cyan-500/20 uppercase tracking-widest">
          {selectedCat}
        </span>
      </div>

      <div className="bg-slate-900/60 rounded-[2.5rem] border border-slate-800 p-6 sm:p-10 mb-6 backdrop-blur-2xl shadow-2xl space-y-8 ring-1 ring-slate-700/30 relative">
        <div className="space-y-4">
          <div className="flex justify-between items-center">
            <label className="text-[10px] uppercase font-black tracking-[0.3em] text-slate-600 ml-1">Input Metric</label>
            <span className="px-2 py-0.5 bg-slate-950 rounded text-[9px] text-cyan-500 font-mono font-bold border border-slate-800">{fromUnit?.symbol}</span>
          </div>
          <div className="flex flex-col gap-2">
            <select 
              className="bg-transparent text-slate-400 text-sm font-bold uppercase tracking-widest focus:outline-none cursor-pointer hover:text-cyan-400 transition-colors"
              value={fromUnit?.name}
              onChange={(e) => setFromUnit(UNIT_DATABASE[selectedCat].find(u => u.name === e.target.value) || null)}
            >
              {UNIT_DATABASE[selectedCat].map(u => <option key={u.name} value={u.name} className="bg-slate-900 text-slate-100">{u.name}</option>)}
            </select>
            <div className="text-4xl font-light mono text-slate-100 overflow-x-auto whitespace-nowrap scrollbar-hide py-2 border-b border-slate-800/50">
              {inputValue}
            </div>
          </div>
        </div>

        <div className="relative h-[1px] bg-slate-800/50 flex items-center justify-center">
           <button 
             onClick={swapUnits}
             className="absolute p-3 bg-slate-950 rounded-full border border-slate-800 shadow-xl hover:bg-slate-800 hover:border-cyan-500/50 transition-all active:scale-90 z-10"
           >
             <ArrowRightLeft className="w-5 h-5 text-cyan-500" />
           </button>
        </div>

        <div className="space-y-4 pt-4">
          <div className="flex justify-between items-center">
            <label className="text-[10px] uppercase font-black tracking-[0.3em] text-slate-600 ml-1">Resulting Output</label>
            <span className="px-2 py-0.5 bg-slate-950 rounded text-[9px] text-cyan-500 font-mono font-bold border border-slate-800">{toUnit?.symbol}</span>
          </div>
          <div className="flex flex-col gap-2">
            <select 
              className="bg-transparent text-slate-400 text-sm font-bold uppercase tracking-widest focus:outline-none cursor-pointer hover:text-cyan-400 transition-colors"
              value={toUnit?.name}
              onChange={(e) => setToUnit(UNIT_DATABASE[selectedCat].find(u => u.name === e.target.value) || null)}
            >
              {UNIT_DATABASE[selectedCat].map(u => <option key={u.name} value={u.name} className="bg-slate-900 text-slate-100">{u.name}</option>)}
            </select>
            <div className="flex items-center justify-between gap-4 pt-2">
               <div className="text-5xl font-black mono text-cyan-400 truncate drop-shadow-[0_0_20px_rgba(34,211,238,0.3)]">
                {outputValue}
               </div>
               <button 
                onClick={copyToClipboard}
                className={`p-2 rounded-lg transition-all ${copied ? 'bg-emerald-500/20 text-emerald-500' : 'text-slate-600 hover:text-slate-300'}`}
               >
                 {copied ? <Check className="w-5 h-5" /> : <Copy className="w-5 h-5" />}
               </button>
            </div>
          </div>
        </div>
      </div>

      {/* Formula Intelligence Card */}
      <div className="mb-8 group">
        <button 
          onClick={() => setShowFormula(!showFormula)}
          className="w-full flex items-center justify-between p-4 bg-slate-900/40 border border-slate-800 rounded-2xl hover:bg-slate-800/60 transition-all"
        >
          <div className="flex items-center gap-3">
            <Cpu className="w-4 h-4 text-cyan-500" />
            <span className="text-[10px] font-black uppercase tracking-widest text-slate-300">Conversion Intelligence</span>
          </div>
          <Info className={`w-4 h-4 transition-transform ${showFormula ? 'text-cyan-500' : 'text-slate-600'}`} />
        </button>

        {showFormula && (
          <div className="mt-2 p-4 bg-cyan-500/5 border border-cyan-500/10 rounded-2xl animate-in fade-in slide-in-from-top-2 duration-300">
            <div className="flex flex-col gap-1">
              <span className="text-[9px] font-bold text-cyan-500/60 uppercase tracking-widest">Mathematical Logic</span>
              <div className="mono text-xs text-slate-300 bg-slate-950/40 p-3 rounded-lg border border-slate-800/50">
                {getFormula()}
              </div>
            </div>
          </div>
        )}
      </div>

      <div className="grid grid-cols-3 gap-3 pb-32">
        {['1','2','3','4','5','6','7','8','9','.', '0', 'CLR'].map(k => (
          <button 
            key={k} 
            onClick={() => handleKeypad(k)}
            className={`flex items-center justify-center p-6 rounded-3xl font-black text-2xl transition-all active:scale-90 border border-slate-800/80 shadow-lg
              ${k === 'CLR' ? 'bg-rose-500/10 text-rose-500 hover:bg-rose-500/20 active:bg-rose-500/30' : 'bg-slate-800/20 text-slate-100 hover:bg-slate-800/40 active:bg-slate-800/60'}`}
          >
            {k}
          </button>
        ))}
      </div>
    </div>
  );
};

