import React, { useState, useEffect, useRef } from 'react';
import { create, all } from 'mathjs';
import { CalcSubMode, AngleMode } from '../types';
import { Copy, Check, History, Settings2, Sparkles } from 'lucide-react';

const math = create(all);

const Calculator: React.FC = () => {
  const [expression, setExpression] = useState('');
  const [result, setResult] = useState<string | null>(null);
  const [subMode, setSubMode] = useState<CalcSubMode>('SCIENTIFIC');
  const [angleMode, setAngleMode] = useState<AngleMode>('DEG');
  const [history, setHistory] = useState<string[]>([]);
  const [lastAns, setLastAns] = useState<string>('0');
  const [grandTotal, setGrandTotal] = useState<number>(0);
  const [taxRate, setTaxRate] = useState<number>(10); // Default 10%
  const [copied, setCopied] = useState(false);
  const displayRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (displayRef.current) {
      displayRef.current.scrollLeft = displayRef.current.scrollWidth;
    }
  }, [expression]);

  const handlePress = (key: string) => {
    if (key === 'C') {
      setExpression('');
      setResult(null);
    } else if (key === 'DEL') {
      setExpression(prev => prev.slice(0, -1));
    } else if (key === '=') {
      calculateResult();
    } else if (key === 'MODE') {
      setSubMode(prev => prev === 'SCIENTIFIC' ? 'COMMERCIAL' : 'SCIENTIFIC');
    } else if (key === 'DEG/RAD') {
      setAngleMode(prev => prev === 'DEG' ? 'RAD' : 'DEG');
    } else if (key === 'TAX+') {
      applyTax(true);
    } else if (key === 'TAX-') {
      applyTax(false);
    } else if (key === 'GT') {
      setExpression(grandTotal.toString());
      setResult(null);
    } else if (key === 'Ans') {
      setExpression(prev => prev + lastAns);
    } else if (['sin', 'cos', 'tan', 'asin', 'acos', 'atan', 'log', 'ln', 'sqrt', 'abs', 'mean', 'std', 'median'].includes(key)) {
      setExpression(prev => prev + key + '(');
    } else if (key === 'x^y') {
      setExpression(prev => prev + '^');
    } else if (key === 'pi') {
      setExpression(prev => prev + 'pi');
    } else if (key === 'e') {
      setExpression(prev => prev + 'e');
    } else {
      setExpression(prev => prev + key);
    }
  };

  const applyTax = (isAdd: boolean) => {
    try {
      const current = parseFloat(expression || result || '0');
      if (isNaN(current)) return;
      const taxAmount = current * (taxRate / 100);
      const newTotal = isAdd ? current + taxAmount : current - taxAmount;
      const resStr = newTotal.toLocaleString(undefined, { maximumFractionDigits: 4, useGrouping: false });
      setResult(resStr);
      setExpression(resStr);
    } catch (e) {
      setResult('Error');
    }
  };

  const calculateResult = () => {
    if (!expression) return;
    try {
      let expr = expression;
      if (angleMode === 'DEG') {
        expr = expr.replace(/sin\(([^)]+)\)/g, 'sin(($1) deg)');
        expr = expr.replace(/cos\(([^)]+)\)/g, 'cos(($1) deg)');
        expr = expr.replace(/tan\(([^)]+)\)/g, 'tan(($1) deg)');
      }

      const evalRes = math.evaluate(expr);
      const formatted = math.format(evalRes, { precision: 14 });
      const resultStr = formatted.toString();

      setResult(resultStr);
      setLastAns(resultStr);
      setHistory(prev => [expression + ' = ' + resultStr, ...prev].slice(0, 10));

      if (!isNaN(parseFloat(resultStr))) {
        setGrandTotal(prev => prev + parseFloat(resultStr));
      }
    } catch (err) {
      setResult('Error');
    }
  };

  const copyToClipboard = () => {
    if (!result || result === 'Error') return;
    navigator.clipboard.writeText(result);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const getButtonClass = (btn: string) => {
    const base = `flex items-center justify-center rounded-2xl font-bold transition-all duration-200 active:scale-90 border shadow-lg group relative overflow-hidden`;
    const size = subMode === 'SCIENTIFIC' ? 'p-3 text-xs sm:text-sm h-12' : 'p-5 text-lg h-16';

    if (['C', 'DEL'].includes(btn)) return `${base} ${size} bg-rose-500/10 text-rose-500 border-rose-500/20 hover:bg-rose-500/20`;
    if (btn === '=') return `${base} ${size} bg-cyan-500 text-slate-950 border-cyan-400 hover:bg-cyan-400 shadow-cyan-500/20 col-span-1`;
    if (['TAX+', 'TAX-', 'GT', 'Ans'].includes(btn)) return `${base} ${size} bg-amber-500/10 text-amber-500 border-amber-500/20 hover:bg-amber-500/20`;
    if (['+', '-', '*', '/', '(', ')', '^'].includes(btn)) return `${base} ${size} bg-slate-800/60 text-cyan-400 border-slate-700 hover:bg-slate-700/80`;
    if (isNaN(Number(btn)) && btn !== '.') return `${base} ${size} bg-slate-900/40 text-slate-400 border-slate-800 hover:bg-slate-800/40`;
    return `${base} ${size} bg-slate-800/20 text-slate-100 border-slate-800 hover:bg-slate-700/30`;
  };

  return (
    <div className="flex flex-col h-full max-w-xl mx-auto p-2 sm:p-4 animate-in fade-in zoom-in-95 duration-700">
      <div className="flex justify-between items-center mb-4 px-2">
        <div className="flex items-center gap-3">
          <div className="flex flex-col">
            <span className="text-cyan-500 font-black tracking-widest text-[10px] uppercase leading-none mb-1">SciCom v1.9</span>
            <div className="flex gap-1.5">
              <button 
                onClick={() => setSubMode(prev => prev === 'SCIENTIFIC' ? 'COMMERCIAL' : 'SCIENTIFIC')}
                className="px-2.5 py-1 rounded-md bg-slate-900 text-slate-400 text-[8px] font-black border border-slate-800 hover:text-cyan-400 hover:border-cyan-500/30 transition-all uppercase"
              >
                {subMode}
              </button>
              {subMode === 'SCIENTIFIC' && (
                <button 
                  onClick={() => setAngleMode(prev => prev === 'DEG' ? 'RAD' : 'DEG')}
                  className="px-2.5 py-1 rounded-md bg-cyan-500/10 text-cyan-500 text-[8px] font-black border border-cyan-500/20 uppercase"
                >
                  {angleMode}
                </button>
              )}
            </div>
          </div>
        </div>
        <div className="flex items-center gap-4">
           <div className="hidden sm:flex flex-col items-end">
              <span className="text-[7px] text-slate-600 font-bold uppercase tracking-[0.2em]">Proc: Aether-X</span>
              <span className="text-[7px] text-emerald-500 font-bold uppercase tracking-[0.2em]">Status: Nominal</span>
           </div>
           <Settings2 className="w-4 h-4 text-slate-700 hover:text-slate-400 cursor-pointer transition-colors" />
        </div>
      </div>

      <div className="bg-slate-900/60 rounded-[2.5rem] border border-slate-800/80 p-6 mb-6 flex flex-col justify-end items-end min-h-[180px] shadow-2xl backdrop-blur-3xl relative overflow-hidden group ring-1 ring-slate-700/30">
        <div className="absolute top-0 right-0 p-4 opacity-5 group-hover:opacity-10 transition-opacity">
          <Sparkles className="w-20 h-20 text-cyan-500" />
        </div>

        <div className="w-full text-right space-y-2 relative z-10">
          <div className="flex items-center justify-end gap-2 text-slate-600 text-[10px] font-mono tracking-tighter uppercase mb-2">
             <History className="w-3 h-3" />
             <span className="truncate max-w-[200px]">{history[0]?.split('=')[0] || 'No previous ops'}</span>
          </div>

          <div ref={displayRef} className="text-slate-400 text-xl font-medium mono whitespace-nowrap overflow-x-auto scrollbar-hide py-1">
            {expression || '0'}
          </div>

          <div className="flex items-center justify-end gap-4 pt-2">
            <div className="text-cyan-400 text-5xl sm:text-6xl font-black mono truncate drop-shadow-[0_0_25px_rgba(34,211,238,0.4)] tracking-tighter">
              {result || '0'}
            </div>
            {result && result !== 'Error' && (
              <button 
                onClick={copyToClipboard}
                className={`p-3 rounded-2xl transition-all active:scale-90 ${copied ? 'bg-emerald-500/20 text-emerald-500' : 'bg-slate-800/40 text-slate-500 hover:text-slate-200'}`}
              >
                {copied ? <Check className="w-5 h-5" /> : <Copy className="w-5 h-5" />}
              </button>
            )}
          </div>
        </div>
      </div>

      <div className={`grid gap-2.5 ${subMode === 'SCIENTIFIC' ? 'grid-cols-5' : 'grid-cols-4'}`}>
        {(subMode === 'SCIENTIFIC' 
          ? ['sin','cos','tan','log','ln','asin','acos','atan','abs','sqrt','^','(',')','pi','e','7','8','9','/','DEL','4','5','6','*','C','1','2','3','-','Ans','0','.','=','+']
          : ['TAX+','TAX-','GT','/','7','8','9','*','4','5','6','-','1','2','3','+','C','0','.','DEL','=']
        ).map((key) => (
          <button 
            key={key} 
            onClick={() => handlePress(key)} 
            className={`${getButtonClass(key)} ${key === '=' && subMode === 'COMMERCIAL' ? 'col-span-1' : ''}`}
          >
            <span className="relative z-10">
              {key === '^' ? 'xʸ' : key === 'pi' ? 'π' : key === '*' ? '×' : key === '/' ? '÷' : key}
            </span>
            <div className="absolute inset-0 bg-gradient-to-br from-white/5 to-transparent opacity-0 group-active:opacity-100 transition-opacity"></div>
          </button>
        ))}
      </div>
    </div>
  );
};

export default Calculator;

import React, { useState, useEffect } from 'react';
import { UnitCategory, Unit } from '../types';
import { UNIT_DATABASE } from '../constants';
import { ChevronRight, ArrowRightLeft, Search, Copy, Check, Info, Cpu, FlaskConical } from 'lucide-react';

const Converter: React.FC = () => {
  const [selectedCat, setSelectedCat] = useState<UnitCategory | null>(null);
  const [fromUnit, setFromUnit] = useState<Unit | null>(null);
  const [toUnit, setToUnit] = useState<Unit | null>(null);
  const [inputValue, setInputValue] = useState('1');
  const [outputValue, setOutputValue] = useState('0');
  const [searchQuery, setSearchQuery] = useState('');
  const [copied, setCopied] = useState(false);
  const [showFormula, setShowFormula] = useState(true);

  const categories = Object.keys(UNIT_DATABASE) as UnitCategory[];

  const filteredCategories = categories.filter(cat => {
    const query = searchQuery.toLowerCase().trim();
    if (!query) return true;
    const catMatch = cat.toLowerCase().includes(query);
    const unitMatch = UNIT_DATABASE[cat].some(unit => 
      unit.name.toLowerCase().includes(query) || 
      unit.symbol.toLowerCase().includes(query)
    );
    return catMatch || unitMatch;
  }).sort((a, b) => a.localeCompare(b));

  useEffect(() => {
    if (selectedCat && fromUnit && toUnit) calculate();
  }, [inputValue, fromUnit, toUnit, selectedCat]);

  const selectCategory = (cat: UnitCategory) => {
    setSelectedCat(cat);
    setFromUnit(UNIT_DATABASE[cat][0]);
    setToUnit(UNIT_DATABASE[cat][1] || UNIT_DATABASE[cat][0]);
    setInputValue('1');
  };

  const calculate = () => {
    if (!selectedCat || !fromUnit || !toUnit) return;
    try {
      const val = parseFloat(inputValue);
      if (isNaN(val)) { setOutputValue('0'); return; }
      let res = 0;
      if (selectedCat === "Temperature") {
        const f = fromUnit.factor as string, t = toUnit.factor as string;
        let c = val;
        if (f === "F") c = (val - 32) * 5 / 9; else if (f === "K") c = val - 273.15; else if (f === "R") c = (val - 491.67) * 5 / 9;
        if (t === "C") res = c; else if (t === "F") res = (c * 9 / 5) + 32; else if (t === "K") res = c + 273.15; else if (t === "R") res = (c * 9 / 5) + 491.67;
      } else if (selectedCat === "Fuel Consumption") {
        const f = fromUnit.factor as string, t = toUnit.factor as string;
        let l = val;
        if (f === "KML") l = 100 / val; else if (f === "MPG_US") l = 235.215 / val; else if (f === "MPG_UK") l = 282.481 / val;
        if (t === "L100") res = l; else if (t === "KML") res = 100 / l; else if (t === "MPG_US") res = 235.215 / l; else if (t === "MPG_UK") res = 282.481 / l;
      } else {
        res = (val * (fromUnit.factor as number)) / (toUnit.factor as number);
      }
      setOutputValue(res.toLocaleString(undefined, { maximumFractionDigits: 10, useGrouping: false }));
    } catch (e) { setOutputValue('Error'); }
  };

  const handleKeypad = (k: string) => {
    if (k === 'CLR') setInputValue('0');
    else if (k === '.') { if (!inputValue.includes('.')) setInputValue(p => p + '.'); }
    else setInputValue(p => p === '0' ? k : p + k);
  };

  if (!selectedCat) {
    return (
      <div className="flex flex-col w-full max-w-2xl mx-auto px-2 animate-in fade-in slide-in-from-bottom-4 duration-700">
        <div className="mb-8 px-2">
          <h2 className="text-4xl font-black text-white tracking-tighter mb-1">UNIVERSE <span className="text-cyan-500">PRO</span></h2>
          <p className="text-slate-500 text-[10px] font-black uppercase tracking-[0.4em]">Multi-Dimensional Metric Array</p>
        </div>

        <div className="sticky top-0 z-20 py-4 bg-slate-950/80 backdrop-blur-lg px-2">
          <div className="relative group">
            <div className="absolute left-6 top-1/2 -translate-y-1/2 text-slate-500 group-focus-within:text-cyan-400 transition-colors">
              <Search className="w-5 h-5" />
            </div>
            <input 
              type="text" 
              placeholder="Search by name or symbol (e.g. 'kg', 'm', 'psi')..."
              className="w-full bg-slate-900/40 border border-slate-800/80 rounded-[2rem] py-5 pl-14 pr-6 text-slate-100 placeholder:text-slate-600 focus:outline-none focus:ring-2 focus:ring-cyan-500/30 focus:border-cyan-500/50 transition-all shadow-2xl"
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
            />
          </div>
        </div>

        <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 pb-32 mt-6 px-2">
          {filteredCategories.map(cat => (
            <button
              key={cat}
              onClick={() => selectCategory(cat)}
              className="group flex items-center justify-between p-6 bg-slate-900/20 border border-slate-800/40 rounded-3xl hover:bg-slate-800/60 hover:border-cyan-500/40 transition-all active:scale-[0.98] shadow-lg"
            >
              <div className="flex flex-col items-start text-left">
                <div className="flex items-center gap-2 mb-1">
                  <FlaskConical className="w-3 h-3 text-cyan-500 opacity-50 group-hover:opacity-100 transition-opacity" />
                  <span className="text-slate-200 font-black tracking-tight group-hover:text-white transition-colors uppercase text-sm">{cat}</span>
                </div>
                <span className="text-[9px] text-slate-600 group-hover:text-slate-400 uppercase font-bold tracking-[0.15em] transition-colors">
                  {UNIT_DATABASE[cat].length} Metrics Loaded
                </span>
              </div>
              <ChevronRight className="w-5 h-5 text-slate-800 group-hover:text-cyan-400 group-hover:translate-x-1 transition-all" />
            </button>
          ))}
        </div>
      </div>
    );
  }

  return (
    <div className="flex flex-col w-full max-w-xl mx-auto px-2 animate-in fade-in duration-700">
      <div className="flex items-center justify-between mb-8 px-2">
        <button onClick={() => setSelectedCat(null)} className="text-[10px] font-black uppercase tracking-[0.2em] text-slate-500 hover:text-cyan-400 flex items-center gap-2 transition-all group">
          <ArrowRightLeft className="w-4 h-4 rotate-90 group-hover:-translate-y-0.5 transition-transform" />
          Systems Library
        </button>
        <div className="px-5 py-2 bg-cyan-500/5 text-cyan-500 rounded-2xl text-[10px] font-black border border-cyan-500/20 uppercase tracking-[0.2em]">
          {selectedCat}
        </div>
      </div>

      <div className="bg-slate-900/60 rounded-[3rem] border border-slate-800/80 p-8 sm:p-12 mb-8 backdrop-blur-3xl shadow-2xl space-y-10 ring-1 ring-slate-700/20 relative">
        <div className="space-y-5">
          <div className="flex justify-between items-center px-1">
            <label className="text-[10px] uppercase font-black tracking-[0.4em] text-slate-600">Source Metric</label>
            <span className="text-[10px] text-cyan-500 font-mono font-bold bg-slate-950 px-3 py-1 rounded-lg border border-slate-800">{fromUnit?.symbol}</span>
          </div>
          <div className="flex flex-col gap-3">
            <select 
              className="bg-transparent text-slate-400 text-xs font-black uppercase tracking-[0.2em] focus:outline-none cursor-pointer hover:text-cyan-400 transition-colors"
              value={fromUnit?.name}
              onChange={(e) => setFromUnit(UNIT_DATABASE[selectedCat].find(u => u.name === e.target.value) || null)}
            >
              {UNIT_DATABASE[selectedCat].map(u => <option key={u.name} value={u.name} className="bg-slate-950">{u.name}</option>)}
            </select>
            <div className="text-5xl font-light mono text-white overflow-x-auto whitespace-nowrap scrollbar-hide py-3 border-b border-slate-800/50">
              {inputValue}
            </div>
          </div>
        </div>

        <div className="relative flex items-center justify-center">
           <button 
             onClick={() => { const t = fromUnit; setFromUnit(toUnit); setToUnit(t); }}
             className="absolute p-4 bg-slate-950 rounded-full border border-slate-800 shadow-2xl hover:bg-slate-800 hover:border-cyan-500/50 transition-all active:scale-90 z-10"
