import React, { useState, useEffect, useRef } from 'react';
import { create, all } from 'mathjs';
import { CalcSubMode, AngleMode } from '../types';
import { Copy, Check, History, Settings2, Sparkles } from 'lucide-react';
import { triggerHaptic } from '../App';

const math = create(all);

const Calculator: React.FC = () => {
  const [expression, setExpression] = useState('');
  const [result, setResult] = useState<string | null>(null);
  const [subMode, setSubMode] = useState<CalcSubMode>('SCIENTIFIC');
  const [angleMode, setAngleMode] = useState<AngleMode>('DEG');
  const [history, setHistory] = useState<string[]>([]);
  const [lastAns, setLastAns] = useState<string>('0');
  const [grandTotal, setGrandTotal] = useState<number>(0);
  const [taxRate, setTaxRate] = useState<number>(10);
  const [copied, setCopied] = useState(false);
  const displayRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (displayRef.current) {
      displayRef.current.scrollLeft = displayRef.current.scrollWidth;
    }
  }, [expression]);

  const handlePress = (key: string) => {
    triggerHaptic(12); // Tactile click

    if (key === 'C') {
      setExpression('');
      setResult(null);
    } else if (key === 'DEL') {
      setExpression(prev => prev.slice(0, -1));
    } else if (key === '=') {
      calculateResult();
    } else if (key === 'Ans') {
      setExpression(prev => prev + lastAns);
    } else if (['sin', 'cos', 'tan', 'asin', 'acos', 'atan', 'log', 'ln', 'sqrt', 'abs'].includes(key)) {
      setExpression(prev => prev + key + '(');
    } else if (key === 'TAX+') {
      applyTax(true);
    } else if (key === 'TAX-') {
      applyTax(false);
    } else if (key === 'GT') {
      setExpression(grandTotal.toString());
      setResult(null);
    } else {
      setExpression(prev => prev + key);
    }
  };

  const applyTax = (isAdd: boolean) => {
    try {
      const current = parseFloat(expression || result || '0');
      if (isNaN(current)) return;
      const taxAmount = current * (taxRate / 100);
      const newTotal = isAdd ? current + taxAmount : current - taxAmount;
      const resStr = newTotal.toLocaleString(undefined, { maximumFractionDigits: 4, useGrouping: false });
      setResult(resStr);
      setExpression(resStr);
    } catch (e) {
      setResult('Error');
    }
  };

  const calculateResult = () => {
    if (!expression) return;
    try {
      let expr = expression.replace(/×/g, '*').replace(/÷/g, '/');
      if (angleMode === 'DEG') {
        expr = expr.replace(/sin\(([^)]+)\)/g, 'sin(($1) deg)');
        expr = expr.replace(/cos\(([^)]+)\)/g, 'cos(($1) deg)');
        expr = expr.replace(/tan\(([^)]+)\)/g, 'tan(($1) deg)');
      }

      const evalRes = math.evaluate(expr);
      const formatted = math.format(evalRes, { precision: 14 });
      const resultStr = formatted.toString();

      setResult(resultStr);
      setLastAns(resultStr);
      setHistory(prev => [expression + ' = ' + resultStr, ...prev].slice(0, 10));

      if (!isNaN(parseFloat(resultStr))) {
        setGrandTotal(prev => prev + parseFloat(resultStr));
      }
    } catch (err) {
      setResult('Error');
    }
  };

  const getButtonClass = (btn: string) => {
    const base = `flex items-center justify-center rounded-2xl font-black transition-all active:scale-[0.85] border shadow-lg relative overflow-hidden h-14 sm:h-16 text-lg`;

    if (['C', 'DEL'].includes(btn)) return `${base} bg-rose-500/10 text-rose-500 border-rose-500/20`;
    if (btn === '=') return `${base} bg-cyan-500 text-slate-950 border-cyan-400 shadow-cyan-500/20`;
    if (['+', '-', '*', '/', '×', '÷'].includes(btn)) return `${base} bg-slate-800/60 text-cyan-400 border-slate-700`;
    if (isNaN(Number(btn)) && btn !== '.') return `${base} bg-slate-900/40 text-slate-500 border-slate-800 text-sm`;
    return `${base} bg-slate-800/20 text-slate-100 border-slate-800`;
  };

  return (
    <div className="flex flex-col animate-in fade-in zoom-in-95 duration-500">
      <div className="flex justify-between items-center mb-4">
        <div className="flex gap-2">
          <button 
            onClick={() => { triggerHaptic(8); setSubMode(prev => prev === 'SCIENTIFIC' ? 'COMMERCIAL' : 'SCIENTIFIC'); }}
            className="px-3 py-1.5 rounded-lg bg-slate-900 text-slate-400 text-[9px] font-black border border-slate-800 uppercase tracking-widest"
          >
            {subMode}
          </button>
          {subMode === 'SCIENTIFIC' && (
            <button 
              onClick={() => { triggerHaptic(8); setAngleMode(prev => prev === 'DEG' ? 'RAD' : 'DEG'); }}
              className="px-3 py-1.5 rounded-lg bg-cyan-500/10 text-cyan-500 text-[9px] font-black border border-cyan-500/20 uppercase tracking-widest"
            >
              {angleMode}
            </button>
          )}
        </div>
      </div>

      <div className="bg-slate-900/60 rounded-[2.5rem] border border-slate-800/80 p-8 mb-6 flex flex-col justify-end items-end min-h-[180px] shadow-2xl backdrop-blur-3xl relative overflow-hidden group">
        <div className="absolute top-0 right-0 p-4 opacity-5 pointer-events-none"><Sparkles className="w-16 h-16 text-cyan-500" /></div>
        <div className="w-full text-right z-10">
          <div className="text-slate-600 text-[10px] font-mono mb-2 uppercase tracking-tighter flex items-center justify-end gap-2">
             <History className="w-3 h-3" />
             {history[0]?.split('=')[0] || 'READY_STATE'}
          </div>
          <div ref={displayRef} className="text-slate-400 text-xl font-medium mono whitespace-nowrap overflow-x-auto scrollbar-hide mb-2">
            {expression || '0'}
          </div>
          <div className="text-cyan-400 text-5xl sm:text-7xl font-black mono truncate tracking-tighter drop-shadow-[0_0_15px_rgba(34,211,238,0.3)]">
            {result || '0'}
          </div>
        </div>
      </div>

      <div className={`grid gap-3 ${subMode === 'SCIENTIFIC' ? 'grid-cols-5' : 'grid-cols-4'}`}>
        {(subMode === 'SCIENTIFIC' 
          ? ['sin','cos','tan','log','ln','asin','acos','atan','abs','sqrt','7','8','9','/','DEL','4','5','6','*','C','1','2','3','-','Ans','0','.','=','+']
          : ['TAX+','TAX-','GT','/','7','8','9','*','4','5','6','-','1','2','3','+','C','0','.','DEL','=']
        ).map((key) => (
          <button 
            key={key} 
            onClick={() => handlePress(key)} 
            className={getButtonClass(key)}
          >
            {key === '*' ? '×' : key === '/' ? '÷' : key}
          </button>
        ))}
      </div>
    </div>
  );
};

