import React, { useState, useEffect, useRef } from 'react';
import { create, all } from 'mathjs';
import { CalcSubMode, AngleMode } from '../types';
import { History, Sparkles } from 'lucide-react';
import { triggerHaptic } from '../App';

const math = create(all);

const Calculator: React.FC = () => {
  const [expression, setExpression] = useState('');
  const [result, setResult] = useState<string | null>(null);
  const [subMode, setSubMode] = useState<CalcSubMode>('SCIENTIFIC');
  const [angleMode, setAngleMode] = useState<AngleMode>('DEG');
  const [history, setHistory] = useState<string[]>([]);
  const [lastAns, setLastAns] = useState<string>('0');
  const [grandTotal, setGrandTotal] = useState<number>(0);
  const [taxRate, setTaxRate] = useState<number>(10);
  const displayRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (displayRef.current) displayRef.current.scrollLeft = displayRef.current.scrollWidth;
  }, [expression]);

  const handlePress = (key: string) => {
    triggerHaptic(8);
    if (key === 'C') { setExpression(''); setResult(null); }
    else if (key === 'DEL') setExpression(prev => prev.slice(0, -1));
    else if (key === '=') calculateResult();
    else if (key === 'Ans') setExpression(prev => prev + lastAns);
    else if (['sin', 'cos', 'tan', 'asin', 'acos', 'atan', 'log', 'ln', 'sqrt', 'abs'].includes(key)) setExpression(prev => prev + key + '(');
    else if (key === 'TAX+') applyTax(true);
    else if (key === 'TAX-') applyTax(false);
    else if (key === 'GT') { setExpression(grandTotal.toString()); setResult(null); }
    else setExpression(prev => prev + key);
  };

  const applyTax = (isAdd: boolean) => {
    try {
      const current = parseFloat(expression || result || '0');
      if (isNaN(current)) return;
      const taxAmount = current * (taxRate / 100);
      const newTotal = isAdd ? current + taxAmount : current - taxAmount;
      const resStr = newTotal.toLocaleString(undefined, { maximumFractionDigits: 4, useGrouping: false });
      setResult(resStr);
      setExpression(resStr);
    } catch (e) { setResult('Error'); }
  };

  const calculateResult = () => {
    if (!expression) return;
    try {
      let expr = expression.replace(/×/g, '*').replace(/÷/g, '/');
      if (angleMode === 'DEG') {
        expr = expr.replace(/sin\(([^)]+)\)/g, 'sin(($1) deg)');
        expr = expr.replace(/cos\(([^)]+)\)/g, 'cos(($1) deg)');
        expr = expr.replace(/tan\(([^)]+)\)/g, 'tan(($1) deg)');
      }
      const evalRes = math.evaluate(expr);
      const formatted = math.format(evalRes, { precision: 14 });
      const resultStr = formatted.toString();
      setResult(resultStr);
      setLastAns(resultStr);
      setHistory(prev => [expression + ' = ' + resultStr, ...prev].slice(0, 10));
      if (!isNaN(parseFloat(resultStr))) setGrandTotal(prev => prev + parseFloat(resultStr));
    } catch (err) { setResult('Error'); }
  };

  const getButtonClass = (btn: string) => {
    const base = `flex items-center justify-center rounded-[1.2rem] font-bold transition-all active:scale-[0.8] border shadow-sm relative overflow-hidden text-lg sm:text-xl w-full h-full`;
    if (['C', 'DEL'].includes(btn)) return `${base} bg-rose-500/10 text-rose-500 border-rose-500/20`;
    if (btn === '=') return `${base} bg-cyan-500 text-slate-950 border-cyan-400 shadow-cyan-500/30`;
    if (['+', '-', '*', '/', '×', '÷'].includes(btn)) return `${base} bg-slate-900/80 text-cyan-400 border-slate-800`;
    if (['TAX+', 'TAX-', 'GT'].includes(btn)) return `${base} bg-slate-800/40 text-emerald-400 border-slate-700/50 text-xs font-black`;
    if (isNaN(Number(btn)) && btn !== '.') return `${base} bg-slate-900/40 text-slate-500 border-slate-800/50 text-xs uppercase font-black`;
    return `${base} bg-slate-800/20 text-slate-100 border-slate-800/80 hover:bg-slate-800/40`;
  };

  const getSpanClass = (key: string) => {
    // Scientific Spans
    if (subMode === 'SCIENTIFIC' && key === '0') return 'col-span-2';

    // Commercial Spans
    if (subMode === 'COMMERCIAL' && key === '=') return 'col-span-4';

    return '';
  };

  return (
    <div className="h-full flex flex-col pb-24 px-4 pt-2 animate-in fade-in duration-500">
      <div className="flex-none flex items-center justify-between mb-2">
         <div className="flex gap-1.5 p-1 bg-slate-900/50 rounded-xl border border-slate-800">
            <button onClick={() => { triggerHaptic(5); setSubMode(subMode === 'SCIENTIFIC' ? 'COMMERCIAL' : 'SCIENTIFIC'); }} className={`px-4 py-1.5 rounded-lg text-[8px] font-black uppercase tracking-widest transition-all ${subMode === 'SCIENTIFIC' ? 'bg-slate-800 text-white' : 'text-slate-600'}`}>Scientific</button>
            <button onClick={() => { triggerHaptic(5); setSubMode(subMode === 'COMMERCIAL' ? 'SCIENTIFIC' : 'COMMERCIAL'); }} className={`px-4 py-1.5 rounded-lg text-[8px] font-black uppercase tracking-widest transition-all ${subMode === 'COMMERCIAL' ? 'bg-slate-800 text-white' : 'text-slate-600'}`}>Business</button>
         </div>
         {subMode === 'SCIENTIFIC' && (
           <button onClick={() => { triggerHaptic(5); setAngleMode(angleMode === 'DEG' ? 'RAD' : 'DEG'); }} className="px-4 py-2 bg-cyan-500/5 border border-cyan-500/20 text-cyan-500 text-[8px] font-black rounded-xl uppercase tracking-widest">{angleMode}</button>
         )}
      </div>

      <div className="flex-none h-[25%] min-h-[140px] bg-slate-900/40 rounded-[2rem] border border-slate-800/60 p-6 mb-4 flex flex-col justify-end items-end shadow-2xl backdrop-blur-3xl relative overflow-hidden group">
        <div className="absolute top-0 right-0 p-6 opacity-[0.03]"><Sparkles className="w-24 h-24 text-cyan-500" /></div>
        <div className="w-full text-right z-10 flex flex-col h-full justify-between">
          <div className="text-slate-600 text-[9px] font-black uppercase tracking-[0.2em] flex items-center justify-end gap-2 border-b border-slate-800/50 pb-2">
             <History className="w-3 h-3" />
             <span className="truncate max-w-[150px]">{history[0]?.split('=')[0] || 'Ready'}</span>
          </div>
          <div className="flex flex-col justify-end">
            <div ref={displayRef} className="text-slate-400 text-lg font-medium mono whitespace-nowrap overflow-x-auto scrollbar-hide mb-1 opacity-80">
                {expression || '0'}
            </div>
            <div className="text-white text-5xl sm:text-6xl font-black mono truncate tracking-tighter drop-shadow-[0_10px_10px_rgba(0,0,0,0.5)] leading-none">
                {result || '0'}
            </div>
          </div>
        </div>
      </div>

      <div className={`flex-1 grid gap-2.5 ${subMode === 'SCIENTIFIC' ? 'grid-cols-5 grid-rows-6' : 'grid-cols-4 grid-rows-6'}`}>
        {(subMode === 'SCIENTIFIC' 
          ? ['sin','cos','tan','log','ln','asin','acos','atan','abs','sqrt','7','8','9','/','DEL','4','5','6','*','C','1','2','3','-','Ans','0','.','=','+']
          : ['TAX+','TAX-','GT','/','7','8','9','*','4','5','6','-','1','2','3','+','C','0','.','DEL','=']
        ).map((key) => (
          <button key={key} onClick={() => handlePress(key)} className={`${getButtonClass(key)} ${getSpanClass(key)}`}>
            {key === '*' ? '×' : key === '/' ? '÷' : key}
          </button>
        ))}
      </div>
    </div>
  );
};

export default Calculator;

import React, { useState, useEffect } from 'react';
import { AppMode } from './types';
import Calculator from './components/Calculator';
import Converter from './components/Converter';
import { Calculator as CalcIcon, Repeat, Zap, ShieldCheck, WifiOff, BatteryFull, BatteryLow, Cpu, Info } from 'lucide-react';

// Global haptic feedback utility
export const triggerHaptic = (intensity: number = 10) => {
  if ('vibrate' in navigator) {
    navigator.vibrate(intensity);
  }
};

const App: React.FC = () => {
  const [mode, setMode] = useState<AppMode>('CALCULATOR');
  const [isLoaded, setIsLoaded] = useState(false);
  const [isOffline, setIsOffline] = useState(!navigator.onLine);
  const [batteryLevel, setBatteryLevel] = useState<number | null>(null);
  const [showSystemInfo, setShowSystemInfo] = useState(false);

  useEffect(() => {
    const timer = setTimeout(() => setIsLoaded(true), 2000);

    if ('getBattery' in navigator) {
      (navigator as any).getBattery().then((battery: any) => {
        setBatteryLevel(Math.round(battery.level * 100));
        battery.addEventListener('levelchange', () => setBatteryLevel(Math.round(battery.level * 100)));
      });
    }

    const handleOnline = () => setIsOffline(false);
    const handleOffline = () => setIsOffline(true);
    window.addEventListener('online', handleOnline);
    window.addEventListener('offline', handleOffline);

    return () => {
      clearTimeout(timer);
      window.removeEventListener('online', handleOnline);
      window.removeEventListener('offline', handleOffline);
    };
  }, []);

  if (!isLoaded) {
    return (
      <div className="fixed inset-0 bg-slate-950 flex flex-col items-center justify-center p-8 text-center z-[100] overflow-hidden">
        <div className="absolute inset-0 opacity-10 pointer-events-none">
          <div className="absolute top-0 left-0 w-full h-full bg-[radial-gradient(circle_at_center,_var(--tw-gradient-stops))] from-cyan-500/20 via-transparent to-transparent"></div>
        </div>
        <div className="relative mb-10 scale-125">
          <div className="absolute inset-0 bg-cyan-500 blur-[80px] opacity-30 animate-pulse"></div>
          <Zap className="w-20 h-20 text-cyan-400 relative z-10 animate-pulse" />
        </div>
        <h1 className="text-4xl font-black text-white tracking-tighter mb-2">OMNISENSE <span className="text-cyan-500">PRO</span></h1>
        <div className="flex items-center gap-2 text-slate-500 text-[10px] font-black uppercase tracking-[0.4em] mb-12">
          <Cpu className="w-3 h-3" />
          <span>ATHER-X CORE Initializing...</span>
        </div>
        <div className="w-56 h-[2px] bg-slate-900 rounded-full overflow-hidden">
          <div className="h-full bg-cyan-500 animate-[boot_2s_ease-in-out_forwards]"></div>
        </div>
        <style>{`@keyframes boot { 0% { width: 0% } 100% { width: 100% } }`}</style>
      </div>
    );
  }

  return (
    <div className="h-full bg-slate-950 flex flex-col overflow-hidden relative selection:bg-cyan-500/30 safe-pt">
      {/* Background Ambience */}
      <div className="fixed inset-0 pointer-events-none -z-10">
        <div className="absolute top-0 right-[-10%] w-[120%] h-[40%] bg-cyan-900/10 blur-[120px] rounded-full"></div>
        <div className="absolute bottom-0 left-[-10%] w-[120%] h-[40%] bg-indigo-900/10 blur-[120px] rounded-full"></div>
      </div>

      {/* Mini System Bar */}
      <header className="flex-none px-6 py-4 flex items-center justify-between border-b border-slate-900/50 bg-slate-950/20 backdrop-blur-md z-50">
        <div className="flex items-center gap-3">
          <div className="w-8 h-8 bg-cyan-500 rounded-lg flex items-center justify-center shadow-lg shadow-cyan-500/20">
            <Zap className="w-5 h-5 text-slate-950" />
          </div>
          <div>
            <h2 className="text-sm font-black text-white tracking-tight leading-none uppercase">OmniSense</h2>
          </div>
        </div>
        <div className="flex items-center gap-3">
           <button onClick={() => { triggerHaptic(5); setShowSystemInfo(!showSystemInfo); }} className="p-2 text-slate-500 hover:text-white transition-colors">
              <Info className="w-4 h-4" />
           </button>
           <div className="flex items-center gap-1.5 px-3 py-1 bg-slate-900/50 rounded-full border border-slate-800">
             {batteryLevel !== null && (
                <div className="flex items-center gap-1.5">
                  {batteryLevel > 20 ? <BatteryFull className="w-3 h-3 text-emerald-500" /> : <BatteryLow className="w-3 h-3 text-rose-500" />}
                  <span className="text-[9px] font-black text-slate-300">{batteryLevel}%</span>
                </div>
             )}
             <div className="w-[1px] h-3 bg-slate-800 mx-1"></div>
             {isOffline ? <WifiOff className="w-3 h-3 text-amber-500" /> : <ShieldCheck className="w-3 h-3 text-cyan-500" />}
           </div>
        </div>
      </header>

      {/* Main Content Area - Full Height & No Scroll by default */}
      <main className="flex-1 overflow-hidden relative z-0">
        {mode === 'CALCULATOR' ? (
           <Calculator />
        ) : (
           <div className="h-full overflow-y-auto pb-32 pt-4 px-4 scrollbar-hide">
             <Converter />
           </div>
        )}
      </main>

      {/* Native Bottom Navigation */}
      <nav className="fixed bottom-0 left-0 right-0 bg-slate-950/90 backdrop-blur-3xl border-t border-slate-900/80 px-6 pb-8 pt-4 flex items-center justify-around z-50 safe-pb shadow-[0_-10px_40px_rgba(0,0,0,0.5)]">
        <button 
          onClick={() => { triggerHaptic(15); setMode('CALCULATOR'); }}
          className={`flex flex-col items-center gap-1.5 transition-all duration-300 active:scale-95 ${mode === 'CALCULATOR' ? 'text-cyan-400 scale-110' : 'text-slate-600'}`}
        >
          <CalcIcon className="w-6 h-6" />
          <span className="text-[8px] font-black uppercase tracking-widest">Compute</span>
        </button>
        <button 
          onClick={() => { triggerHaptic(15); setMode('CONVERTER'); }}
          className={`flex flex-col items-center gap-1.5 transition-all duration-300 active:scale-95 ${mode === 'CONVERTER' ? 'text-cyan-400 scale-110' : 'text-slate-600'}`}
        >
          <Repeat className="w-6 h-6" />
          <span className="text-[8px] font-black uppercase tracking-widest">Metrics</span>
        </button>
      </nav>

      {/* System Overlay */}
      {showSystemInfo && (
        <div className="fixed inset-0 z-[60] bg-slate-950/90 backdrop-blur-xl p-10 flex flex-col items-center justify-center animate-in fade-in duration-300">
           <Zap className="w-16 h-16 text-cyan-500 mb-6" />
           <h4 className="text-xl font-black text-white mb-2">OmniSense</h4>
           <p className="text-slate-500 text-center text-xs mb-10 max-w-xs leading-relaxed uppercase font-bold tracking-widest">Enterprise grade toolset designed for precision computing and metric synchronization.</p>
           <button onClick={() => setShowSystemInfo(false)} className="px-8 py-3 bg-cyan-500 text-slate-950 font-black rounded-2xl uppercase text-[10px] tracking-widest">Acknowledge</button>
        </div>
      )}
    </div>
  );
};

export default App;
